#include<bits/stdc++.h>
using namespace std;
const long long mod=999911658;
long long n,g,jc[50010],a[5],b[5]={0,2,3,4679,35617},val;
long long fastpow(long long x,long long y,long long p)
{
    long long ans=1;
    while(y)
    {
        if(y&1)
        {
            ans=ans*x%p;
        }
        x=x*x%p;
        y>>=1;
    }
    return ans;
}
void init(long long p)
{
    jc[0]=1;
    for(long long i=1;i<=p;i++)
    {
        jc[i]=jc[i-1]*i%mod;
    }
}
long long C(long long n,long long m,long long p)
{
    if(n<m)
    {
        return 0;
    }
    return jc[n]*fastpow(jc[m],p-2,p)%p*fastpow(jc[n-m],p-2,p)%p;
}
long long lucas(long long n,long long m,long long p)
{
    if(n<m)
    {
        return 0;
    }
    if(n==0)
    {
        return 1;
    }
    return lucas(n/p,m/p,p)*C(n%p,m%p,p)%p;
}
void crt()
{
    for(int i=1;i<=4;i++)
    {
        val=(val+a[i]*(mod/b[i])%mod*fastpow(mod/b[i],b[i]-2,b[i]))%mod;
    }
}
int main()
{
    scanf("%lld%lld",&n,&g);
    if(g%(mod+1)==0)
    {
        printf("0");
        return 0;
    }
    for(long long i=1;i<=4;i++)
    {
        init(b[i]);
        for(long long j=1;j*j<=n;j++)
        {
            if(n%j==0)
            {
                a[i]=(a[i]+lucas(n,j,b[i]))%b[i];
                if(j*j==n)
                {
                    continue;
                }
                j=n/j;
                a[i]=(a[i]+lucas(n,j,b[i]))%b[i];
                j=n/j;
            }
        }
    }
    crt();
    printf("%lld",fastpow(g,val,mod+1));
    return 0;
}
